    vector<int> spf(MAX, 0);

    for (int i = 2; i < MAX; ++i) {
        if (spf[i] == 0) {
            spf[i] = i;
            for (int j = i * 2; j < MAX; j += i) {
                if (spf[j] == 0) {
                    spf[j] = i;
                }
            }
        }
    }

    // Preprocess the prime_to_indices map
    unordered_map<int, vector<int>> prime_to_indices;
    for (int i = 0; i < n; ++i) {
        long long x = nums[i];
        if (x == 1) continue;
        vector<int> primes;
        long long temp = x;
        while (temp > 1) {
            int p = spf[temp];
            while (temp % p == 0) {
                temp /= p;
            }
            primes.push_back(p);
        }
        for (int p : primes) {
            prime_to_indices[p].push_back(i);
        }
    }

    // BFS
    vector<bool> visited(n, false);
    queue<int> q;
    q.push(0);
    visited[0] = true;
    int steps = 0;

